import{_ as n,o as s,c as e,ag as t}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Async/Await & Goroutines","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concurrency/async.md","filePath":"guide/concurrency/async.md"}'),o={name:"guide/concurrency/async.md"};function i(c,a,l,r,p,d){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="async-await-goroutines" tabindex="-1">Async/Await &amp; Goroutines <a class="header-anchor" href="#async-await-goroutines" aria-label="Permalink to &quot;Async/Await &amp; Goroutines&quot;">​</a></h1><p>Vex provides two primary concurrency models designed for modern parallel systems:</p><ol><li><strong>Async/Await</strong>: Stackless coroutines for managing many I/O-bound operations efficiently.</li><li><strong>Goroutines</strong>: Lightweight, M:N scheduled green threads for CPU-bound parallelism.</li></ol><h2 id="async-functions" tabindex="-1">Async Functions <a class="header-anchor" href="#async-functions" aria-label="Permalink to &quot;Async Functions&quot;">​</a></h2><p>Async functions are declared with the <code>async</code> keyword and return a future that can be awaited.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>async fn fetch_data(id: i32): i32 {</span></span>
<span class="line"><span>    println(f&quot;Fetching data for ID: {id}&quot;)</span></span>
<span class="line"><span>    await sleep(100) // Suspend current coroutine</span></span>
<span class="line"><span>    return id * 2</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="the-await-keyword" tabindex="-1">The <code>await</code> Keyword <a class="header-anchor" href="#the-await-keyword" aria-label="Permalink to &quot;The \`await\` Keyword&quot;">​</a></h2><p>Vex uses <strong>prefix await</strong> syntax to wait for asynchronous results:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>async fn process() {</span></span>
<span class="line"><span>    let result = await fetch_data(42)</span></span>
<span class="line"><span>    println(f&quot;Result: {result}&quot;)</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="goroutines-go" tabindex="-1">Goroutines (<code>go</code>) <a class="header-anchor" href="#goroutines-go" aria-label="Permalink to &quot;Goroutines (\`go\`)&quot;">​</a></h2><p>The <code>go</code> keyword spawns a lightweight thread (goroutine) that runs concurrently with the caller.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn heavy_task() {</span></span>
<span class="line"><span>    // ... complex computation ...</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn main() {</span></span>
<span class="line"><span>    go heavy_task() // Run in background</span></span>
<span class="line"><span>    go {</span></span>
<span class="line"><span>        println(&quot;Inline goroutine&quot;)</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="channels" tabindex="-1">Channels <a class="header-anchor" href="#channels" aria-label="Permalink to &quot;Channels&quot;">​</a></h2><p>Channels provide safe, synchronized communication between goroutines and async tasks.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main() {</span></span>
<span class="line"><span>    let! ch = Channel.new&lt;i32&gt;(10)</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    go {</span></span>
<span class="line"><span>        ch.send(42)</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    let val = ch.recv() // Some(42)</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="channel-operations" tabindex="-1">Channel Operations <a class="header-anchor" href="#channel-operations" aria-label="Permalink to &quot;Channel Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th></tr></thead><tbody><tr><td><code>Channel.new&lt;T&gt;(cap)</code></td><td>Create a channel with fixed capacity</td></tr><tr><td><code>ch.send(val)</code></td><td>Send a value (may block)</td></tr><tr><td><code>ch.recv()</code></td><td>Receive a value (returns <code>Option&lt;T&gt;</code>)</td></tr><tr><td><code>ch.close()</code></td><td>Close the channel</td></tr></tbody></table><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Use <code>async</code> for I/O</strong>: High-concurrency network or disk tasks should use <code>async/await</code>.</li><li><strong>Use <code>go</code> for CPU work</strong>: Offload heavy computations to goroutines to avoid blocking the async event loop.</li><li><strong>Communicate via Channels</strong>: Avoid shared memory where possible; leverage channels for state synchronization.</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/concurrency/sync">Synchronization</a> - Mutexes and atomics</li><li><a href="/docs/guide/stdlib">Standard Library</a> - Built-in async utilities</li><li><a href="/docs/guide/memory/borrowing">Memory Safety</a> - Thread-safe borrowing</li></ul>`,21)])])}const g=n(o,[["render",i]]);export{u as __pageData,g as default};
